import type { SyntaxNodeRef } from '@lezer/common';

import { convertToErrorNode } from './node-mutations.js';
import type {
  FilterFieldFlatNode,
  FilterFieldLogicalOperatorNode,
} from '../../../types/conversion-utils.js';
import type { FilterFieldError } from '../../../types/filter-field-error.js';
import { getTextFromRange } from '../../get-text.js';

/**
 * Convert a logical operator node.
 * @internal
 */
export function convertLogicalOperator(
  node: SyntaxNodeRef,
  doc: string,
): { convertedNode: FilterFieldFlatNode; errors: FilterFieldError[] } {
  const { from, to } = node;
  const textValue = getTextFromRange(
    node,
    doc,
  ).trim() as FilterFieldLogicalOperatorNode['value'];
  const uppercasedTextValue =
    textValue.toUpperCase() as FilterFieldLogicalOperatorNode['value'];

  const convertedNode: FilterFieldLogicalOperatorNode = {
    type: 'LogicalOperator',
    range: {
      from,
      to,
    },
    textValue: uppercasedTextValue,
    value: uppercasedTextValue,
  };
  const errors: FilterFieldError[] = [];

  // Check for invalid position of the logical operator.
  const treeCursor = node.node.cursor();
  if (
    // Check if there is either no next sibling or the next sibling is a closing bracket or logicalOperator.
    !treeCursor.nextSibling() ||
    treeCursor.node.type.name === 'ClosingBracket' ||
    treeCursor.node.type.name === 'LogicalOperator' ||
    // Check if there is no previous sibling.
    (treeCursor.prevSibling() &&
      (!treeCursor.prevSibling() ||
        treeCursor.node.type.name === 'OpeningBracket'))
  ) {
    convertToErrorNode(convertedNode);
    convertedNode.textValue = textValue;
    convertedNode.value = textValue;
    errors.push({
      range: { from, to },
      message: 'invalidLogicalOperator',
    });
  }

  return {
    convertedNode,
    errors,
  };
}
